-- 4. 타임슬롯 (매장별 월~토 런치/디너)
-- day_of_week: 0=일, 1=월, ..., 6=토
DO $$
DECLARE
  r_id UUID;
  d INT;
BEGIN
  FOR r_id IN
    SELECT id FROM restaurants WHERE id IN (
      'a0000001-0001-4000-8000-000000000001',
      'a0000001-0002-4000-8000-000000000002',
      'a0000001-0003-4000-8000-000000000003',
      'a0000001-0004-4000-8000-000000000004',
      'a0000001-0005-4000-8000-000000000005',
      'a0000001-0006-4000-8000-000000000006',
      'a0000001-0007-4000-8000-000000000007',
      'a0000001-0008-4000-8000-000000000008'
    )
  LOOP
    FOR d IN 1..6 LOOP  -- 월~토
      INSERT INTO restaurant_time_slots (restaurant_id, day_of_week, slot_time, max_reservations, is_active)
      VALUES
        (r_id, d, '11:30', 5, true),
        (r_id, d, '12:00', 5, true),
        (r_id, d, '12:30', 5, true),
        (r_id, d, '18:00', 5, true),
        (r_id, d, '18:30', 5, true),
        (r_id, d, '19:00', 5, true),
        (r_id, d, '19:30', 5, true),
        (r_id, d, '20:00', 4, true)
      ON CONFLICT (restaurant_id, day_of_week, slot_time) DO NOTHING;
    END LOOP;
  END LOOP;
END $$;
